import{_ as a,v as t,f as r,i as o}from"./chunks/framework.jfF5glnW.js";const _=JSON.parse('{"title":"Week 4 | 电子焊接练习","description":"","frontmatter":{"title":"Week 4 | 电子焊接练习","date":"2026-03-24T00:00:00.000Z","tags":["课程周志","电子焊接","硬件制作"],"cover":"/code2real_blog/posts/week4/megumi.jpg"},"headers":[],"relativePath":"posts/week4.md","filePath":"posts/week4.md"}'),s={name:"posts/week4.md"};function p(i,e,l,n,d,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<p>第四周从软件建模转入电子制作实践。本周主要学习焊接工具使用、焊点质量判断和基础操作规范。</p><hr><img src="/code2real_blog/posts/week4/megumi.jpg" alt="Week 4 image"><h2 id="本周学习内容" tabindex="-1">本周学习内容 <a class="header-anchor" href="#本周学习内容" aria-label="Permalink to &quot;本周学习内容&quot;">​</a></h2><p>本周的重点是电子焊接。课程中接触了电烙铁、焊锡丝、烙铁架、镊子、斜口钳和吸锡工具等基本工具，并学习了元件插装、焊接、剪脚和检查焊点的完整流程。</p><p>焊接看起来只是把元件固定到电路板上，但实际要求比想象中细。焊盘和引脚需要同时受热，焊锡要自然润湿接触面，而不是堆在表面。这个过程对手部稳定性、加热时间和焊锡用量都有要求。</p><h2 id="实践过程" tabindex="-1">实践过程 <a class="header-anchor" href="#实践过程" aria-label="Permalink to &quot;实践过程&quot;">​</a></h2><p>实践中先从简单元件开始，把元件插入孔位后翻转电路板，用烙铁同时接触焊盘和引脚，再送入少量焊锡。焊点完成后还要观察表面是否光滑、是否包住引脚，最后剪掉多余引脚。</p><p>练习过程中也开始注意烙铁头状态。烙铁头如果氧化或没有及时清洁，传热效果会明显下降，焊锡也不容易附着。后来每次焊接前后都会简单清洁烙铁头，操作稳定性比一开始好很多。</p><h2 id="遇到的问题" tabindex="-1">遇到的问题 <a class="header-anchor" href="#遇到的问题" aria-label="Permalink to &quot;遇到的问题&quot;">​</a></h2><p>最常见的问题是焊锡用量不好控制。锡太多时焊点会变得臃肿，严重时会连到旁边焊盘；锡太少又容易形成虚焊，表面看着接上了，实际连接并不可靠。</p><p>另一个问题是刚开始只盯着元件引脚加热，忽略了焊盘同步受热。这样焊锡只是附在引脚上，焊点强度和导电性都不稳定。后面调整操作习惯后，焊点形状明显更自然。</p><h2 id="本周收获" tabindex="-1">本周收获 <a class="header-anchor" href="#本周收获" aria-label="Permalink to &quot;本周收获&quot;">​</a></h2><p>本周让我认识到，硬件制作中的细节会直接影响结果。焊接不是附属步骤，而是电路能否稳定工作的基础。</p><p>和前三周的软件练习相比，焊接的问题更直接，也更难靠撤销键解决。每一次加热时间、送锡角度和元件位置都会留下实际结果，这让我对实体制作的容错成本有了更清楚的认识。</p>',15)])])}const m=a(s,[["render",p]]);export{_ as __pageData,m as default};
